import{_ as e,o as d,c as o,ag as r}from"./chunks/framework.D4O_uTxf.js";const u=JSON.parse('{"title":"Traceability Matrix","description":"","frontmatter":{},"headers":[],"relativePath":"traceability/TRACEABILITY_MATRIX.md","filePath":"traceability/TRACEABILITY_MATRIX.md","lastUpdated":1771844172000}'),a={name:"traceability/TRACEABILITY_MATRIX.md"};function c(s,t,n,i,l,h){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="traceability-matrix" tabindex="-1">Traceability Matrix <a class="header-anchor" href="#traceability-matrix" aria-label="Permalink to &quot;Traceability Matrix&quot;">​</a></h1><p><strong>Status:</strong> Living document — updated as FRs are assigned, implemented, and tested. <strong>Format:</strong> FR ID | Requirement Summary (SHALL) | Spec Doc | Crate / Source Path | Test Name Pattern | Status</p><p>Status values: <code>planned</code> | <code>in_progress</code> | <code>implemented</code></p><hr><h2 id="core-engine-fr-core" tabindex="-1">Core Engine (FR-CORE-*) <a class="header-anchor" href="#core-engine-fr-core" aria-label="Permalink to &quot;Core Engine (FR-CORE-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0001-core-simulation-loop.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-CORE-001</td><td>The engine SHALL advance simulation state by exactly one tick per <code>Engine::step()</code> invocation.</td><td>CIV-0001</td><td><code>crates/engine/src/tick.rs</code></td><td><code>tick::step_advances_tick</code></td><td>implemented</td></tr><tr><td>FR-CORE-002</td><td>The engine SHALL produce identical output for identical seed and input sequence (determinism).</td><td>CIV-0001</td><td><code>crates/engine/src/lib.rs</code></td><td><code>determinism::double_run_identical</code></td><td>implemented</td></tr><tr><td>FR-CORE-003</td><td>The engine SHALL use ChaCha20Rng seeded per-run; no global mutable RNG state.</td><td>CIV-0001</td><td><code>crates/engine/src/rng.rs</code></td><td><code>rng::chacha20_seeded_isolated</code></td><td>implemented</td></tr><tr><td>FR-CORE-004</td><td>Each tick SHALL complete within 100 ms wall-clock on the reference hardware profile.</td><td>CIV-0001</td><td><code>crates/engine/src/tick.rs</code></td><td><code>perf::tick_under_100ms</code></td><td>in_progress</td></tr><tr><td>FR-CORE-005</td><td>The engine SHALL emit a BLAKE3 hash of full world state at the end of every tick.</td><td>CIV-0001</td><td><code>crates/engine/src/hash_chain.rs</code></td><td><code>hash_chain::tick_hash_emitted</code></td><td>implemented</td></tr><tr><td>FR-CORE-006</td><td>Consecutive tick hashes SHALL form an append-only chain (each hash includes prior hash).</td><td>CIV-0001</td><td><code>crates/engine/src/hash_chain.rs</code></td><td><code>hash_chain::chain_includes_prior</code></td><td>implemented</td></tr><tr><td>FR-CORE-007</td><td>The engine SHALL surface a <code>run.hash.mismatch.v1</code> event when replayed state diverges.</td><td>CIV-0001</td><td><code>crates/engine/src/integrity.rs</code></td><td><code>integrity::mismatch_event_emitted</code></td><td>in_progress</td></tr><tr><td>FR-CORE-008</td><td>World state SHALL be modelled as bevy_ecs 0.18.x <code>World</code>; no global singletons.</td><td>CIV-0001</td><td><code>crates/engine/src/world.rs</code></td><td><code>world::no_global_resources</code></td><td>planned</td></tr><tr><td>FR-CORE-009</td><td>Hex grid SHALL use <code>hexx</code> 0.21.x axial coordinates throughout engine and render crates.</td><td>CIV-0001</td><td><code>crates/engine/src/grid.rs</code></td><td><code>grid::axial_roundtrip</code></td><td>planned</td></tr><tr><td>FR-CORE-010</td><td>All integer quantities SHALL use fixed-point types (<code>FixedI32&lt;U16&gt;</code>, <code>i64</code> KiloJoules, <code>i64</code> MilliCredits).</td><td>CIV-0001</td><td><code>crates/engine/src/numerics.rs</code></td><td><code>numerics::no_float_in_state</code></td><td>planned</td></tr></tbody></table><hr><h2 id="economy-fr-econ" tabindex="-1">Economy (FR-ECON-*) <a class="header-anchor" href="#economy-fr-econ" aria-label="Permalink to &quot;Economy (FR-ECON-*)&quot;">​</a></h2><p>Source specs: <code>docs/specs/CIV-0100-economy.md</code>, <code>docs/specs/CIV-0107-joule-economy.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-ECON-001</td><td>Each district SHALL produce Joules each tick according to its resource type and capacity.</td><td>CIV-0100</td><td><code>crates/economy/src/production.rs</code></td><td><code>production::district_produces_joules</code></td><td>implemented</td></tr><tr><td>FR-ECON-002</td><td>Joule consumption SHALL be deducted from district reserves before regional distribution.</td><td>CIV-0107</td><td><code>crates/economy/src/consumption.rs</code></td><td><code>consumption::deducted_before_distribution</code></td><td>implemented</td></tr><tr><td>FR-ECON-003</td><td>Joule consumption per tick SHALL never be negative (consumption_non_negative invariant).</td><td>CIV-0107</td><td><code>crates/economy/src/consumption.rs</code></td><td><code>consumption::consumption_non_negative</code></td><td>implemented</td></tr><tr><td>FR-ECON-004</td><td>Surplus Joules SHALL flow to adjacent districts via the distribution graph each tick.</td><td>CIV-0100</td><td><code>crates/economy/src/distribution.rs</code></td><td><code>distribution::surplus_flows_adjacent</code></td><td>in_progress</td></tr><tr><td>FR-ECON-005</td><td>Waste heat SHALL be computed as a percentage of total Joules consumed per tick.</td><td>CIV-0107</td><td><code>crates/economy/src/waste.rs</code></td><td><code>waste::heat_computed_from_consumption</code></td><td>planned</td></tr><tr><td>FR-ECON-006</td><td>GDP SHALL be derived from sum of regional Joule throughput converted at a fixed exchange rate.</td><td>CIV-0100</td><td><code>crates/economy/src/gdp.rs</code></td><td><code>gdp::sum_of_regional_joules</code></td><td>planned</td></tr><tr><td>FR-ECON-007</td><td>Trade agreements SHALL transfer Joules and MilliCredits between civilizations each tick.</td><td>CIV-0100</td><td><code>crates/economy/src/trade.rs</code></td><td><code>trade::bilateral_transfer_balanced</code></td><td>planned</td></tr><tr><td>FR-ECON-008</td><td>A district in Joule deficit for 3 consecutive ticks SHALL emit <code>economy.district.collapsed.v1</code>.</td><td>CIV-0100</td><td><code>crates/economy/src/district.rs</code></td><td><code>district::collapse_after_deficit_ticks</code></td><td>planned</td></tr><tr><td>FR-ECON-009</td><td>Subsistence mode SHALL activate when a civilization&#39;s total Joule balance drops below threshold.</td><td>CIV-0107</td><td><code>crates/economy/src/subsistence.rs</code></td><td><code>subsistence::activates_below_threshold</code></td><td>planned</td></tr><tr><td>FR-ECON-010</td><td>Treasury balance SHALL be tracked in MilliCredits (<code>i64</code>) with no floating-point accumulation.</td><td>CIV-0100</td><td><code>crates/economy/src/treasury.rs</code></td><td><code>treasury::milliCredits_no_float</code></td><td>planned</td></tr></tbody></table><hr><h2 id="level-of-detail-fr-lod" tabindex="-1">Level of Detail (FR-LOD-*) <a class="header-anchor" href="#level-of-detail-fr-lod" aria-label="Permalink to &quot;Level of Detail (FR-LOD-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0101-lod.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-LOD-001</td><td>The engine SHALL support two zoom levels: strategic (region) and operational (district/hex).</td><td>CIV-0101</td><td><code>crates/engine/src/lod.rs</code></td><td><code>lod::two_levels_defined</code></td><td>planned</td></tr><tr><td>FR-LOD-002</td><td>Strategic view SHALL aggregate district data into region summaries each tick.</td><td>CIV-0101</td><td><code>crates/engine/src/lod.rs</code></td><td><code>lod::strategic_aggregation</code></td><td>planned</td></tr><tr><td>FR-LOD-003</td><td>LOD transitions SHALL not alter simulation state, only view projection.</td><td>CIV-0101</td><td><code>crates/engine/src/lod.rs</code></td><td><code>lod::transition_no_state_mutation</code></td><td>planned</td></tr><tr><td>FR-LOD-004</td><td>Operational view SHALL expose individual hex-cell resource and population data.</td><td>CIV-0101</td><td><code>crates/engine/src/lod.rs</code></td><td><code>lod::operational_hex_data_visible</code></td><td>planned</td></tr></tbody></table><hr><h2 id="climate-fr-clim" tabindex="-1">Climate (FR-CLIM-*) <a class="header-anchor" href="#climate-fr-clim" aria-label="Permalink to &quot;Climate (FR-CLIM-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0102-climate.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-CLIM-001</td><td>Atmospheric CO2 SHALL accumulate each tick based on industrial Joule consumption.</td><td>CIV-0102</td><td><code>crates/climate/src/co2.rs</code></td><td><code>co2::accumulates_with_consumption</code></td><td>planned</td></tr><tr><td>FR-CLIM-002</td><td>Global mean temperature SHALL be derived from CO2 concentration via parameterised formula.</td><td>CIV-0102</td><td><code>crates/climate/src/temperature.rs</code></td><td><code>temperature::derived_from_co2</code></td><td>planned</td></tr><tr><td>FR-CLIM-003</td><td>The engine SHALL emit <code>climate.threshold.crossed.v1</code> when temperature crosses a defined level.</td><td>CIV-0102</td><td><code>crates/climate/src/events.rs</code></td><td><code>climate_events::threshold_event_emitted</code></td><td>planned</td></tr><tr><td>FR-CLIM-004</td><td>Climate damage SHALL reduce district Joule production capacity when temperature exceeds threshold.</td><td>CIV-0102</td><td><code>crates/climate/src/damage.rs</code></td><td><code>damage::reduces_production_above_threshold</code></td><td>planned</td></tr><tr><td>FR-CLIM-005</td><td>The engine SHALL model at least one tipping-point cascade (e.g. ice-albedo) above critical temperature.</td><td>CIV-0102</td><td><code>crates/climate/src/tipping.rs</code></td><td><code>tipping::cascade_triggered</code></td><td>planned</td></tr><tr><td>FR-CLIM-006</td><td>Civilizations SHALL be able to invest MilliCredits into adaptation to reduce climate damage.</td><td>CIV-0102</td><td><code>crates/climate/src/adaptation.rs</code></td><td><code>adaptation::investment_reduces_damage</code></td><td>planned</td></tr></tbody></table><hr><h2 id="institutions-fr-inst" tabindex="-1">Institutions (FR-INST-*) <a class="header-anchor" href="#institutions-fr-inst" aria-label="Permalink to &quot;Institutions (FR-INST-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0103-institutions.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-INST-001</td><td>Each civilization SHALL have an institutional type (democracy, autocracy, technocracy, etc.).</td><td>CIV-0103</td><td><code>crates/institutions/src/governance.rs</code></td><td><code>governance::type_assigned_at_init</code></td><td>planned</td></tr><tr><td>FR-INST-002</td><td>Institutional capture score SHALL accumulate each tick based on resource concentration.</td><td>CIV-0103</td><td><code>crates/institutions/src/capture.rs</code></td><td><code>capture::accumulates_with_concentration</code></td><td>planned</td></tr><tr><td>FR-INST-003</td><td>The engine SHALL emit <code>institution.capture.threshold.v1</code> when capture crosses 0.75.</td><td>CIV-0103</td><td><code>crates/institutions/src/events.rs</code></td><td><code>inst_events::capture_threshold_event</code></td><td>planned</td></tr><tr><td>FR-INST-004</td><td>Institutional collapse SHALL trigger a governance type transition.</td><td>CIV-0103</td><td><code>crates/institutions/src/collapse.rs</code></td><td><code>collapse::triggers_type_transition</code></td><td>planned</td></tr><tr><td>FR-INST-005</td><td>Institution time-series data SHALL be stored in the metrics DB for post-run analysis.</td><td>CIV-0103</td><td><code>crates/db/src/institution_series.rs</code></td><td><code>db::institution_series_stored</code></td><td>planned</td></tr><tr><td>FR-INST-006</td><td>Citizen lifecycle (birth, migration, death) SHALL be driven by institutional and economic state.</td><td>CIV-0103</td><td><code>crates/citizens/src/lifecycle.rs</code></td><td><code>lifecycle::driven_by_inst_economy</code></td><td>planned</td></tr></tbody></table><hr><h2 id="theorem-invariants-fr-thry" tabindex="-1">Theorem / Invariants (FR-THRY-*) <a class="header-anchor" href="#theorem-invariants-fr-thry" aria-label="Permalink to &quot;Theorem / Invariants (FR-THRY-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0104-theorem.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-THRY-001</td><td>Total Joule energy in a closed system SHALL be conserved each tick (production - consumption - waste = 0).</td><td>CIV-0104</td><td><code>crates/engine/src/invariants.rs</code></td><td><code>invariants::joule_conservation</code></td><td>planned</td></tr><tr><td>FR-THRY-002</td><td>Total MilliCredit supply SHALL remain constant absent explicit treasury mint/burn operations.</td><td>CIV-0104</td><td><code>crates/engine/src/invariants.rs</code></td><td><code>invariants::credit_supply_conserved</code></td><td>planned</td></tr><tr><td>FR-THRY-003</td><td>Population delta per tick SHALL equal births minus deaths minus emigration plus immigration.</td><td>CIV-0104</td><td><code>crates/engine/src/invariants.rs</code></td><td><code>invariants::population_delta_balanced</code></td><td>planned</td></tr><tr><td>FR-THRY-004</td><td>The invariant checker SHALL run every tick and panic in debug builds on violation.</td><td>CIV-0104</td><td><code>crates/engine/src/invariants.rs</code></td><td><code>invariants::checker_panics_on_violation</code></td><td>planned</td></tr></tbody></table><hr><h2 id="diplomacy-fr-dipl" tabindex="-1">Diplomacy (FR-DIPL-*) <a class="header-anchor" href="#diplomacy-fr-dipl" aria-label="Permalink to &quot;Diplomacy (FR-DIPL-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0105-war-diplomacy.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-DIPL-001</td><td>Civilizations SHALL be able to declare war, producing <code>diplomacy.war.declared.v1</code>.</td><td>CIV-0105</td><td><code>crates/diplomacy/src/war.rs</code></td><td><code>war::declare_emits_event</code></td><td>planned</td></tr><tr><td>FR-DIPL-002</td><td>Peace SHALL be negotiated via signed treaty, producing <code>diplomacy.peace.signed.v1</code>.</td><td>CIV-0105</td><td><code>crates/diplomacy/src/peace.rs</code></td><td><code>peace::signed_emits_event</code></td><td>planned</td></tr><tr><td>FR-DIPL-003</td><td>Treaties SHALL encode terms (trade ratios, non-aggression, alliance) as structured data.</td><td>CIV-0105</td><td><code>crates/diplomacy/src/treaty.rs</code></td><td><code>treaty::terms_structured</code></td><td>planned</td></tr><tr><td>FR-DIPL-004</td><td>Treaty breach SHALL emit <code>diplomacy.treaty.broken.v1</code> and apply reputation penalty.</td><td>CIV-0105</td><td><code>crates/diplomacy/src/treaty.rs</code></td><td><code>treaty::breach_emits_event_and_penalty</code></td><td>planned</td></tr><tr><td>FR-DIPL-005</td><td>Espionage operations SHALL have a configurable detection probability per tick.</td><td>CIV-0105</td><td><code>crates/diplomacy/src/espionage.rs</code></td><td><code>espionage::detection_probability_applied</code></td><td>planned</td></tr><tr><td>FR-DIPL-006</td><td>Detected espionage SHALL emit <code>diplomacy.espionage.detected.v1</code>.</td><td>CIV-0105</td><td><code>crates/diplomacy/src/espionage.rs</code></td><td><code>espionage::detected_emits_event</code></td><td>planned</td></tr><tr><td>FR-DIPL-007</td><td>Shadow networks SHALL model covert influence as a hidden resource accumulating per tick.</td><td>CIV-0105</td><td><code>crates/diplomacy/src/shadow.rs</code></td><td><code>shadow::influence_accumulates</code></td><td>planned</td></tr></tbody></table><hr><h2 id="social-fr-soci" tabindex="-1">Social (FR-SOCI-*) <a class="header-anchor" href="#social-fr-soci" aria-label="Permalink to &quot;Social (FR-SOCI-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0106-social.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-SOCI-001</td><td>Ideological alignment SHALL be tracked per-citizen cohort as a continuous score.</td><td>CIV-0106</td><td><code>crates/social/src/ideology.rs</code></td><td><code>ideology::per_cohort_continuous</code></td><td>planned</td></tr><tr><td>FR-SOCI-002</td><td>Citizen stress SHALL accumulate when Joule access falls below subsistence level.</td><td>CIV-0106</td><td><code>crates/social/src/stress.rs</code></td><td><code>stress::accumulates_below_subsistence</code></td><td>planned</td></tr><tr><td>FR-SOCI-003</td><td>Insurgency SHALL start when aggregate stress exceeds the configured threshold.</td><td>CIV-0106</td><td><code>crates/social/src/insurgency.rs</code></td><td><code>insurgency::starts_above_threshold</code></td><td>planned</td></tr><tr><td>FR-SOCI-004</td><td>The engine SHALL emit <code>social.insurgency.started.v1</code> and <code>social.insurgency.ended.v1</code>.</td><td>CIV-0106</td><td><code>crates/social/src/events.rs</code></td><td><code>social_events::insurgency_lifecycle_events</code></td><td>planned</td></tr><tr><td>FR-SOCI-005</td><td>Health index SHALL be computed from food Joules, clean water, and medical infrastructure.</td><td>CIV-0106</td><td><code>crates/social/src/health.rs</code></td><td><code>health::computed_from_inputs</code></td><td>planned</td></tr><tr><td>FR-SOCI-006</td><td>A health crisis SHALL emit <code>social.health.crisis.v1</code> and reduce labor productivity.</td><td>CIV-0106</td><td><code>crates/social/src/health.rs</code></td><td><code>health::crisis_emits_event_reduces_labor</code></td><td>planned</td></tr></tbody></table><hr><h2 id="ai-fr-ai" tabindex="-1">AI (FR-AI-*) <a class="header-anchor" href="#ai-fr-ai" aria-label="Permalink to &quot;AI (FR-AI-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0400-ai.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-AI-001</td><td>AI civilizations SHALL select actions using a utility scoring function over available moves.</td><td>CIV-0400</td><td><code>crates/ai/src/utility.rs</code></td><td><code>utility::scores_all_moves</code></td><td>planned</td></tr><tr><td>FR-AI-002</td><td>MCTS SHALL be used for multi-step lookahead planning beyond depth 1.</td><td>CIV-0400</td><td><code>crates/ai/src/mcts.rs</code></td><td><code>mcts::lookahead_depth_gt_1</code></td><td>planned</td></tr><tr><td>FR-AI-003</td><td>Each AI leader SHALL have a personality profile affecting utility weights.</td><td>CIV-0400</td><td><code>crates/ai/src/personality.rs</code></td><td><code>personality::weights_differ_per_profile</code></td><td>planned</td></tr><tr><td>FR-AI-004</td><td>Personality drift SHALL accumulate stochastically each N ticks.</td><td>CIV-0400</td><td><code>crates/ai/src/personality.rs</code></td><td><code>personality::drift_accumulates_stochastically</code></td><td>planned</td></tr><tr><td>FR-AI-005</td><td>AI SHALL never exceed a configurable MilliCredit/Joule expenditure per tick (fair-play cap).</td><td>CIV-0400</td><td><code>crates/ai/src/fair_play.rs</code></td><td><code>fair_play::cap_enforced_per_tick</code></td><td>planned</td></tr><tr><td>FR-AI-006</td><td>AI decision events SHALL be emitted for post-run analysis and replay.</td><td>CIV-0400</td><td><code>crates/ai/src/events.rs</code></td><td><code>ai_events::decision_emitted</code></td><td>planned</td></tr><tr><td>FR-AI-007</td><td>MCTS computation time SHALL be capped at a fraction of the 100 ms tick budget.</td><td>CIV-0400</td><td><code>crates/ai/src/mcts.rs</code></td><td><code>mcts::time_capped_within_budget</code></td><td>planned</td></tr></tbody></table><hr><h2 id="protocol-fr-prot" tabindex="-1">Protocol (FR-PROT-*) <a class="header-anchor" href="#protocol-fr-prot" aria-label="Permalink to &quot;Protocol (FR-PROT-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0200-protocol.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-PROT-001</td><td>The engine SHALL expose a JSON-RPC 2.0 API over WebSocket.</td><td>CIV-0200</td><td><code>crates/protocol/src/server.rs</code></td><td><code>protocol::jsonrpc_handshake</code></td><td>planned</td></tr><tr><td>FR-PROT-002</td><td>All events SHALL be emitted as JSON-RPC notifications with a common envelope.</td><td>CIV-0200</td><td><code>crates/protocol/src/events.rs</code></td><td><code>protocol::event_envelope_valid</code></td><td>planned</td></tr><tr><td>FR-PROT-003</td><td>Event envelope SHALL contain <code>event_id</code> (UUIDv7), <code>event_type</code>, <code>session_id</code>, <code>tick</code>, <code>created_at</code>, <code>payload</code>.</td><td>CIV-0200</td><td><code>crates/protocol/src/events.rs</code></td><td><code>protocol::envelope_fields_present</code></td><td>planned</td></tr><tr><td>FR-PROT-004</td><td>The server SHALL persist all emitted events to the DB audit log within the same tick.</td><td>CIV-0200</td><td><code>crates/db/src/audit_log.rs</code></td><td><code>db::events_persisted_same_tick</code></td><td>planned</td></tr><tr><td>FR-PROT-005</td><td>Client connections SHALL authenticate before receiving any session events.</td><td>CIV-0200</td><td><code>crates/protocol/src/auth.rs</code></td><td><code>protocol::unauthenticated_rejected</code></td><td>planned</td></tr><tr><td>FR-PROT-006</td><td>The protocol SHALL support at least 10 concurrent client connections per session.</td><td>CIV-0200</td><td><code>crates/protocol/src/server.rs</code></td><td><code>protocol::concurrent_clients_10</code></td><td>planned</td></tr></tbody></table><hr><h2 id="ui-ux-fr-ux" tabindex="-1">UI/UX (FR-UX-*) <a class="header-anchor" href="#ui-ux-fr-ux" aria-label="Permalink to &quot;UI/UX (FR-UX-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0300-ui-ux.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-UX-001</td><td>The UI SHALL render the hex map using the <code>crates/render</code> crate at 60 fps target.</td><td>CIV-0300</td><td><code>crates/render/src/hex_map.rs</code></td><td><code>render::hex_map_60fps</code></td><td>planned</td></tr><tr><td>FR-UX-002</td><td>The UI SHALL support RTS-style camera pan, zoom, and unit selection.</td><td>CIV-0300</td><td><code>crates/render/src/camera.rs</code></td><td><code>render::rts_camera_controls</code></td><td>planned</td></tr><tr><td>FR-UX-003</td><td>A timeline scrubber SHALL display tick history and allow rewind to any stored tick.</td><td>CIV-0300</td><td><code>crates/render/src/timeline.rs</code></td><td><code>render::timeline_scrubber_rewind</code></td><td>planned</td></tr><tr><td>FR-UX-004</td><td>LOD transitions SHALL be visually seamless within one rendered frame.</td><td>CIV-0300</td><td><code>crates/render/src/lod.rs</code></td><td><code>render::lod_seamless_transition</code></td><td>planned</td></tr><tr><td>FR-UX-005</td><td>All UI state changes SHALL derive from events; no direct engine state polling.</td><td>CIV-0300</td><td><code>crates/render/src/state.rs</code></td><td><code>render::state_from_events_only</code></td><td>planned</td></tr></tbody></table><hr><h2 id="assets-fr-asset" tabindex="-1">Assets (FR-ASSET-*) <a class="header-anchor" href="#assets-fr-asset" aria-label="Permalink to &quot;Assets (FR-ASSET-*)&quot;">​</a></h2><p>Source specs: <code>docs/specs/CIV-0600-2d-assets.md</code>, <code>docs/specs/CIV-0601-3d-assets.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-ASSET-001</td><td>All 2D tile sprites SHALL be derived from SVG sources and rasterised at build time.</td><td>CIV-0600</td><td><code>crates/render/src/atlas.rs</code></td><td><code>asset::svg_rasterised_at_build</code></td><td>planned</td></tr><tr><td>FR-ASSET-002</td><td>The asset pipeline SHALL pack all tile sprites into a single texture atlas per LOD level.</td><td>CIV-0600</td><td><code>crates/render/src/atlas.rs</code></td><td><code>asset::atlas_packed_per_lod</code></td><td>planned</td></tr><tr><td>FR-ASSET-003</td><td>Atlas build SHALL emit <code>asset.atlas.built.v1</code> on success or <code>asset.generation.failed.v1</code> on error.</td><td>CIV-0600</td><td><code>crates/render/src/atlas.rs</code></td><td><code>asset::atlas_build_events</code></td><td>planned</td></tr><tr><td>FR-ASSET-004</td><td>3D assets SHALL be stored as glTF 2.0 and loaded lazily on demand.</td><td>CIV-0601</td><td><code>crates/render/src/gltf.rs</code></td><td><code>asset::gltf_lazy_loaded</code></td><td>planned</td></tr></tbody></table><hr><h2 id="modding-fr-mod" tabindex="-1">Modding (FR-MOD-*) <a class="header-anchor" href="#modding-fr-mod" aria-label="Permalink to &quot;Modding (FR-MOD-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0700-modding.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-MOD-001</td><td>Mods SHALL be loaded from WASM binaries compiled against the published SDK.</td><td>CIV-0700</td><td><code>crates/engine/src/mod_loader.rs</code></td><td><code>modding::wasm_mod_loaded</code></td><td>planned</td></tr><tr><td>FR-MOD-002</td><td>Mod execution SHALL be sandboxed; mods SHALL NOT access host file system or network.</td><td>CIV-0700</td><td><code>crates/engine/src/mod_sandbox.rs</code></td><td><code>modding::sandbox_no_host_access</code></td><td>planned</td></tr><tr><td>FR-MOD-003</td><td>Mod state SHALL be persisted and restored as part of save/load (CIV-1000).</td><td>CIV-0700</td><td><code>crates/engine/src/mod_state.rs</code></td><td><code>modding::state_persisted_restored</code></td><td>planned</td></tr><tr><td>FR-MOD-004</td><td>The engine SHALL emit <code>mod.loaded.v1</code>, <code>mod.unloaded.v1</code>, and <code>mod.error.v1</code> events.</td><td>CIV-0700</td><td><code>crates/engine/src/mod_events.rs</code></td><td><code>modding::lifecycle_events_emitted</code></td><td>planned</td></tr><tr><td>FR-MOD-005</td><td>Mods SHALL be able to register new resource types, policy levers, and event handlers.</td><td>CIV-0700</td><td><code>crates/engine/src/mod_registry.rs</code></td><td><code>modding::can_register_resources</code></td><td>planned</td></tr></tbody></table><hr><h2 id="audio-fr-aud" tabindex="-1">Audio (FR-AUD-*) <a class="header-anchor" href="#audio-fr-aud" aria-label="Permalink to &quot;Audio (FR-AUD-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0800-audio.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-AUD-001</td><td>Background music SHALL be driven by Kira and adapt to game state each tick.</td><td>CIV-0800</td><td><code>crates/render/src/audio.rs</code></td><td><code>audio::kira_initialized</code></td><td>planned</td></tr><tr><td>FR-AUD-002</td><td>Music layers SHALL fade in/out based on tension, prosperity, and war state.</td><td>CIV-0800</td><td><code>crates/render/src/audio.rs</code></td><td><code>audio::layers_respond_to_state</code></td><td>planned</td></tr><tr><td>FR-AUD-003</td><td>SFX SHALL be triggered by specific events (war declared, district collapsed, etc.).</td><td>CIV-0800</td><td><code>crates/render/src/audio.rs</code></td><td><code>audio::sfx_triggered_by_events</code></td><td>planned</td></tr></tbody></table><hr><h2 id="session-fr-sess" tabindex="-1">Session (FR-SESS-*) <a class="header-anchor" href="#session-fr-sess" aria-label="Permalink to &quot;Session (FR-SESS-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0900-pve-session.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-SESS-001</td><td>The engine SHALL support PvE (human vs AI) sessions.</td><td>CIV-0900</td><td><code>crates/engine/src/session.rs</code></td><td><code>session::pve_mode_supported</code></td><td>planned</td></tr><tr><td>FR-SESS-002</td><td>Hot-seat multiplayer SHALL allow multiple human players per session.</td><td>CIV-0900</td><td><code>crates/engine/src/session.rs</code></td><td><code>session::hotseat_multi_human</code></td><td>planned</td></tr><tr><td>FR-SESS-003</td><td>Observer mode SHALL allow read-only session access without influencing simulation.</td><td>CIV-0900</td><td><code>crates/engine/src/session.rs</code></td><td><code>session::observer_read_only</code></td><td>planned</td></tr><tr><td>FR-SESS-004</td><td>Challenge mode SHALL allow async submission of a civilization seed for scoring.</td><td>CIV-0900</td><td><code>crates/engine/src/challenge.rs</code></td><td><code>challenge::async_submission_accepted</code></td><td>planned</td></tr><tr><td>FR-SESS-005</td><td>Session speed SHALL be configurable (1x, 2x, 4x, paused) and emit <code>session.speed_changed.v1</code>.</td><td>CIV-0900</td><td><code>crates/engine/src/session.rs</code></td><td><code>session::speed_change_emits_event</code></td><td>planned</td></tr><tr><td>FR-SESS-006</td><td>Turn boundaries in hot-seat mode SHALL emit <code>session.turn.start.v1</code> and <code>session.turn.end.v1</code>.</td><td>CIV-0900</td><td><code>crates/engine/src/session.rs</code></td><td><code>session::turn_events_emitted</code></td><td>planned</td></tr></tbody></table><hr><h2 id="save-load-fr-save" tabindex="-1">Save / Load (FR-SAVE-*) <a class="header-anchor" href="#save-load-fr-save" aria-label="Permalink to &quot;Save / Load (FR-SAVE-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-1000-save-load.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-SAVE-001</td><td>Quicksave SHALL serialize full world state to a named slot within 500 ms.</td><td>CIV-1000</td><td><code>crates/db/src/save.rs</code></td><td><code>save::quicksave_under_500ms</code></td><td>planned</td></tr><tr><td>FR-SAVE-002</td><td>Save SHALL emit <code>session.saved.v1</code> on success or <code>session.save_failed.v1</code> on error.</td><td>CIV-1000</td><td><code>crates/db/src/save.rs</code></td><td><code>save::save_events_emitted</code></td><td>planned</td></tr><tr><td>FR-SAVE-003</td><td>Load SHALL restore world state to byte-identical engine state (determinism guarantee).</td><td>CIV-1000</td><td><code>crates/db/src/load.rs</code></td><td><code>save::load_restores_identical_state</code></td><td>planned</td></tr><tr><td>FR-SAVE-004</td><td>Autosave SHALL trigger every N ticks (configurable, default 100).</td><td>CIV-1000</td><td><code>crates/db/src/autosave.rs</code></td><td><code>save::autosave_every_n_ticks</code></td><td>planned</td></tr><tr><td>FR-SAVE-005</td><td>Save format SHALL include a schema version; older saves SHALL be rejected with an error (no silent migration).</td><td>CIV-1000</td><td><code>crates/db/src/schema.rs</code></td><td><code>save::old_schema_rejected_explicitly</code></td><td>planned</td></tr></tbody></table><hr><h2 id="performance-fr-perf" tabindex="-1">Performance (FR-PERF-*) <a class="header-anchor" href="#performance-fr-perf" aria-label="Permalink to &quot;Performance (FR-PERF-*)&quot;">​</a></h2><p>Source spec: <code>docs/specs/CIV-0500-performance.md</code></p><table tabindex="0"><thead><tr><th>FR ID</th><th>Requirement Summary</th><th>Spec Doc</th><th>Crate / Source Path</th><th>Test Name Pattern</th><th>Status</th></tr></thead><tbody><tr><td>FR-PERF-001</td><td>The engine SHALL sustain 100 ms/tick (10 ticks/s) with 8 civilizations and 1,000 hex cells.</td><td>CIV-0500</td><td><code>crates/engine/src/tick.rs</code></td><td><code>perf::sustained_10_ticks_per_sec</code></td><td>planned</td></tr><tr><td>FR-PERF-002</td><td>Engine heap allocation per tick SHALL not exceed 1 MiB outside of initial world setup.</td><td>CIV-0500</td><td><code>crates/engine/src/tick.rs</code></td><td><code>perf::heap_under_1mib_per_tick</code></td><td>planned</td></tr><tr><td>FR-PERF-003</td><td>The render crate SHALL maintain 60 fps at 1080p on the reference GPU profile.</td><td>CIV-0500</td><td><code>crates/render/src/frame.rs</code></td><td><code>perf::render_60fps_1080p</code></td><td>planned</td></tr><tr><td>FR-PERF-004</td><td>DB write throughput SHALL not become a bottleneck for tick latency (async writes).</td><td>CIV-0500</td><td><code>crates/db/src/writer.rs</code></td><td><code>perf::db_writes_async_nonblocking</code></td><td>planned</td></tr><tr><td>FR-PERF-005</td><td>JSON-RPC serialization SHALL complete within 5 ms per event batch.</td><td>CIV-0500</td><td><code>crates/protocol/src/serializer.rs</code></td><td><code>perf::serialization_under_5ms</code></td><td>planned</td></tr></tbody></table><hr><p><em>Last updated: 2026-02-21. Maintainer: add new FRs as specs are finalized; update Status as tests are written and pass CI.</em></p>',73)])])}const m=e(a,[["render",c]]);export{u as __pageData,m as default};
